#include<bits/stdc++.h>
using namespace std;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;

const int N = 1e5 + 5;
int a[N], b[N], t[N], pos[N];

int main()
{
	int n;
	cin >> n;
	for(int i = 1; i <= n; i++)
		cin >> a[i];
	for(int i = 1; i <= n; i++)
		cin >> b[i];
	for(int i = 1; i <= n; i++)
		t[b[i]] = i;
	for(int i = 1; i <= n; i++)
		pos[i] = t[a[i]];
	int ans = 0, maxn = 0;
	for(int i = 1; i <= n; i++)
	{
		if(maxn > pos[i]) ans++;
		else maxn = pos[i];
	}
	cout << ans;
}
